    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>().HasIndex(p => p.Sku);
        modelBuilder.Entity<Product>().ToContainer("Products");
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

arguments.new_str:
using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");
            entity.HasIndex(p => p.Sku);

            // EF Core 9 changed the discriminator property from "Discriminator" to "$type".
            // Preserve "Discriminator" so existing 500K documents remain readable and
            // direct SQL queries (WHERE c.Discriminator = 'Product') keep working.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Product");

            // EF Core 9 changed the id format from "Product|<key>" to just "<key>".
            // Preserve the legacy format so existing documents are still addressable.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonProperty("id");
            entity.UseETagConcurrency();
        });

        // Globally preserve the EF Core 8 id format ("EntityType|Key") for all entities.
        // Without this, EF Core 9 won't find existing documents whose ids include the type prefix.
        foreach (var entityType in modelBuilder.Model.GetEntityTypes())
        {
            entityType.SetIdValueGeneratorFactory((_, _) => null);
        }
    }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        base.OnConfiguring(optionsBuilder);
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

