class CosmosQuery
{
    // BREAKING CHANGE 3 — Synchronous query APIs removed.
    // EF Core 9 Cosmos provider no longer supports ToList(), First(), Single(), etc.
    // All queries must use their async counterparts (ToListAsync, FirstAsync, …).
    async System.Threading.Tasks.Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator (preserved via HasDiscriminator config)
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

